INSERT INTO public."News" ("id", "cityId", "title", "content", "imageUrl", "source", "isPublished", "createdAt") VALUES ('cmp8dtxc40026mavt8x0ttj9j', 'cmp8dtxb70000mavt7q4w47pi', 'Choutuppal Municipality Approves New Road Widening Project', 'The Choutuppal Municipality has approved a ₹15 crore road widening project for the Main Road stretch from Bus Stand to Highway Junction. The project is expected to be completed within 18 months and will ease traffic congestion in the town center. Local businesses have welcomed the move while requesting minimal disruption during construction.', NULL, 'Telangana Today', TRUE, '2026-05-16T13:28:49.157Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."News" ("id", "cityId", "title", "content", "imageUrl", "source", "isPublished", "createdAt") VALUES ('cmp8dtxc50028mavt2bdir5ab', 'cmp8dtxb70000mavt7q4w47pi', 'New Water Supply Scheme to Benefit 10,000 Households', 'The state government has sanctioned a new water supply scheme for Choutuppal under the Mission Bhagiratha program. The scheme will provide clean drinking water to over 10,000 households in the town and surrounding areas. Pipeline laying work has already begun and is expected to be completed by March next year.', 'https://images.unsplash.com/photo-1548839140-29a749e1cf4d?w=800', 'Eenadu', TRUE, '2026-05-16T13:28:49.157Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."News" ("id", "cityId", "title", "content", "imageUrl", "source", "isPublished", "createdAt") VALUES ('cmp8dtxc6002amavtg0xak5yv', 'cmp8dtxb70000mavt7q4w47pi', 'Choutuppal RDO Office Inaugurates Digital Services Center', 'The RDO office in Choutuppal has inaugurated a new digital services center that will allow citizens to access various government services online. Services include land records, certificates, and pension applications. The center is equipped with 20 computers and trained staff to assist the public.', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800', 'Namaste Telangana', TRUE, '2026-05-16T13:28:49.158Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."News" ("id", "cityId", "title", "content", "imageUrl", "source", "isPublished", "createdAt") VALUES ('cmp8dtxc6002cmavtuydsu4tx', 'cmp8dtxb70000mavt7q4w47pi', 'Annual Choutuppal Jatara Festival Draws Record Crowds', 'The annual Choutuppal Jatara festival celebrated at the ancient Sri Rama Temple drew record crowds this year with over 50,000 devotees attending the three-day event. The festival featured cultural programs, traditional dances, and a grand procession. Local authorities made elaborate arrangements for crowd management and security.', 'https://images.unsplash.com/photo-1544829099-b9a0c07fad1a?w=800', 'Sakshi', TRUE, '2026-05-16T13:28:49.159Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Blog" ("id", "title", "slug", "coverImageUrl", "content", "authorId", "cityId", "isPublished", "createdAt", "updatedAt") VALUES ('cmp8dtxd1005emavtb3v00zhf', '5 Hidden Gems in Choutuppal You Must Visit', '5-hidden-gems-choutuppal', 'https://images.unsplash.com/photo-1587474260584-136574535ed5?w=800', '<h2>Discover Choutuppal</h2><p>Choutuppal is a town rich in culture and history. Here are 5 places you absolutely must visit...</p>', 'cmp8dtxba0004mavtyqcph9qw', 'cmp8dtxb70000mavt7q4w47pi', TRUE, '2026-05-16T13:28:49.190Z'::timestamp, '2026-05-16T13:28:49.190Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Blog" ("id", "title", "slug", "coverImageUrl", "content", "authorId", "cityId", "isPublished", "createdAt", "updatedAt") VALUES ('cmp8dtxd2005gmavtbxppffu1', 'How Digital Platforms Are Transforming Small Towns', 'digital-platforms-transforming-small-towns', 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=800', '<h2>The Digital Revolution</h2><p>Small towns across India are embracing digital transformation at an unprecedented rate...</p>', 'cmp8dtxba0004mavtyqcph9qw', NULL, TRUE, '2026-05-16T13:28:49.190Z'::timestamp, '2026-05-16T13:28:49.190Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Blog" ("id", "title", "slug", "coverImageUrl", "content", "authorId", "cityId", "isPublished", "createdAt", "updatedAt") VALUES ('cmp8dtxd3005imavtj6t1xn01', 'Best Street Food in Telangana Towns', 'best-street-food-telangana', 'https://images.unsplash.com/photo-1630383249896-424e482df921?w=800', '<h2>Street Food Paradise</h2><p>Telangana is famous for its incredible street food culture. From spicy mirchi bajji to sweet jalebi...</p>', 'cmp8dtxbc0006mavt3bpkbux9', 'cmp8dtxb70000mavt7q4w47pi', TRUE, '2026-05-16T13:28:49.191Z'::timestamp, '2026-05-16T13:28:49.191Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Blog" ("id", "title", "slug", "coverImageUrl", "content", "authorId", "cityId", "isPublished", "createdAt", "updatedAt") VALUES ('cmp8dtxdz007jmavtn7cklf9n', 'Why Every Local Business Needs a Digital Presence in 2025', 'local-business-digital-presence-2025', 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=800', '<h2>The Digital Revolution is Here</h2><p>In 2025, having a digital presence is no longer optional for local businesses. With over 80% of consumers searching online before making a purchase decision, businesses that are not visible online are losing customers every day.</p><h3>Key Benefits</h3><ul><li>Increased visibility in local search results</li><li>Building trust with customer reviews</li><li>Reaching younger demographics who primarily use mobile</li><li>Competing with larger chains on a level playing field</li></ul><p>The Choutuppal Super App makes it easy for local businesses to establish their digital presence without needing technical expertise. Simply list your business, add your services, and start receiving enquiries via WhatsApp!</p>', 'cmp8dtxba0004mavtyqcph9qw', 'cmp8dtxb70000mavt7q4w47pi', TRUE, '2026-05-16T13:28:49.224Z'::timestamp, '2026-05-16T13:28:49.224Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Blog" ("id", "title", "slug", "coverImageUrl", "content", "authorId", "cityId", "isPublished", "createdAt", "updatedAt") VALUES ('cmp8dtxe0007lmavtgvztf9aa', 'How Agents Are Earning ₹20,000+ Monthly with Choutuppal App', 'agent-earnings-guide-2025', 'https://images.unsplash.com/photo-1553729459-uj1ef3f78828?w=800', '<h2>The Agent Opportunity</h2><p>Choutuppal App agents are earning significant commissions by helping local businesses get online. Here is how the commission structure works and how you can maximize your earnings.</p><h3>Commission Structure</h3><ul><li><strong>Listings:</strong> 20% commission on every Pro (₹299) and Premium (₹499) listing you sell</li><li><strong>Banner Ads:</strong> 15% commission on monthly banner ad sales</li><li><strong>News Posts:</strong> 10% commission on sponsored news posts</li></ul><h3>Success Tips</h3><p>Top-performing agents focus on building relationships with business owners. Start with businesses you already know, show them the value of being listed, and the enquiries will speak for themselves.</p>', 'cmp8dtxba0004mavtyqcph9qw', NULL, TRUE, '2026-05-16T13:28:49.224Z'::timestamp, '2026-05-16T13:28:49.224Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Blog" ("id", "title", "slug", "coverImageUrl", "content", "authorId", "cityId", "isPublished", "createdAt", "updatedAt") VALUES ('cmp8dtxe1007nmavtbgv5cqwb', 'Own Your City: The Franchisee Opportunity', 'franchisee-opportunity-guide', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=800', '<h2>Become a City Admin</h2><p>The Choutuppal App franchisee model allows entrepreneurs to own and operate the platform in their city. As a City Admin, you get:</p><ul><li>Full management rights for your city</li><li>30% revenue share from all transactions in your city</li><li>Ability to recruit and manage agents</li><li>Complete content management for listings, news, and banners</li></ul><h3>Investment</h3><p>The one-time franchisee fee is ₹50,000. This gives you exclusive rights to operate in your city with full support from our platform team.</p>', 'cmp8dtxba0004mavtyqcph9qw', NULL, TRUE, '2026-05-16T13:28:49.225Z'::timestamp, '2026-05-16T13:28:49.225Z'::timestamp) ON CONFLICT DO NOTHING;
