INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxeq009mmavtdrwsucg2', 'cmp8dtxbi000imavt8p9exy72', 'చౌటుప్పల్ లో కొత్త రోడ్లు నిర్మాణం జరుగుతోంది... 🚧 మా ప్రభుత్వం ₹15 కోట్లు కేటాయించింది. త్వరలో ట్రాఫిక్ సమస్య తగ్గుతుంది! #ChoutuppalDevelopment #అభివృద్ధి', NULL, 342, 45, TRUE, FALSE, '2026-05-16T13:28:49.250Z'::timestamp, '2026-05-16T13:28:49.250Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxeq009omavtv2z1d6yx', 'cmp8dtxbi000imavt8p9exy72', 'నేడు చౌటుప్పల్ ప్రభుత్వ పాఠశాలలో డిజిటల్ క్లాస్‌రూమ్ ప్రారంభోత్సవం! 🏫💻 పిల్లల భవిష్యత్తు కోసం మేము కట్టుబడి ఉన్నాము. #Education #DigitalIndia', NULL, 228, 32, FALSE, FALSE, '2026-05-16T13:28:49.251Z'::timestamp, '2026-05-16T13:28:49.251Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxer009qmavt9l4rao4h', 'cmp8dtxbi000imavt8p9exy72', 'చౌటుప్పల్ జాతర ఈ ఏడాది ఘనంగా జరుగుతుంది! 🙏 అందరం కలిసి పాల్గొనండి. భక్తుల సౌకర్యార్థం ప్రత్యేక ఏర్పాట్లు చేశాము. 🪔', NULL, 456, 67, FALSE, FALSE, '2026-05-16T13:28:49.251Z'::timestamp, '2026-05-16T13:28:49.251Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxes009smavtbcdvhh7j', 'cmp8dtxbj000kmavtk2a6wkka', 'చౌటుప్పల్ మున్సిపాలిటీ నుండి మీ అందరికీ సందేశం! 🏙️ మంచినీటి సరఫరా పథకం పనులు వేగంగా జరుగుతున్నాయి. మార్చి నాటికి పూర్తవుతుంది! 💧 #MissionBhagiratha', NULL, 189, 23, TRUE, FALSE, '2026-05-16T13:28:49.252Z'::timestamp, '2026-05-16T13:28:49.252Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxes009umavtefpdi5pg', 'cmp8dtxbj000kmavtk2a6wkka', 'స్వచ్ఛ చౌటుప్పల్ - ఆదివారం శుభ్రత కార్యక్రమం! 🧹 అందరం పాల్గొనండి. మన పట్టణం మన బాధ్యత! #SwachhChoutuppal #CleanCity', NULL, 145, 18, FALSE, FALSE, '2026-05-16T13:28:49.253Z'::timestamp, '2026-05-16T13:28:49.253Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxet009wmavt4b1t2rc9', 'cmp8dtxbk000mmavtg6adh05f', 'చౌటుప్పల్ లో బెస్ట్ మసాలా దోశ! 🤤 శ్రీ వెంకటేశ్వర టిఫిన్ సెంటర్ లో ట్రై చేయండి రండి! నాకు ఇది ఎప్పటికీ ఫేవరెట్! ❤️ #ChoutuppalFood #LocalEats', '["https://images.unsplash.com/photo-1630383249896-424e482df921?w=600"]', 567, 89, FALSE, FALSE, '2026-05-16T13:28:49.253Z'::timestamp, '2026-05-16T13:28:49.253Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxeu009ymavtgj559tci', 'cmp8dtxbk000mmavtg6adh05f', 'చౌటుప్పల్ జాతర వైభవం! 🎊✨ ఈ ఏడాది రికార్డు స్థాయిలో భక్తులు వచ్చారు. సాంస్కృతిక కార్యక్రమాలు అద్భుతంగా ఉన్నాయి! 🪔🙏', '["https://images.unsplash.com/photo-1544829099-b9a0c07fad1a?w=600"]', 834, 112, FALSE, FALSE, '2026-05-16T13:28:49.254Z'::timestamp, '2026-05-16T13:28:49.254Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxeu00a0mavtx0j2ijk3', 'cmp8dtxbf000cmavt5aq9r3xj', 'ఈ రోజు చౌటుప్పల్ మార్కెట్ లో కొనుగోలు! 🛍️ కూరగాయల ధరలు ఈ వారం చాలా బాగున్నాయి. టమాటా ₹20/kg, ఉల్లిపచ్చి ₹25/kg 🍅🧅', NULL, 45, 12, FALSE, FALSE, '2026-05-16T13:28:49.255Z'::timestamp, '2026-05-16T13:28:49.255Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxev00a2mavtzrnhsm7m', 'cmp8dtxbf000cmavt5aq9r3xj', 'Choutuppal App is so useful! Found the best salon in town through this app. Lakshmi Beauty Salon did an amazing job with my bridal makeup! 💄✨ Thank you @LakshmiDevi!', NULL, 67, 8, FALSE, FALSE, '2026-05-16T13:28:49.255Z'::timestamp, '2026-05-16T13:28:49.255Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Post" ("id", "authorId", "content", "mediaUrls", "likesCount", "commentsCount", "isPinned", "isDeleted", "createdAt", "updatedAt") VALUES ('cmp8dtxew00a4mavtk5p58hrn', 'cmp8dtxbc0006mavt3bpkbux9', 'శ్రీ వెంకటేశ్వర టిఫిన్ సెంటర్ లో ఈ వారం ప్రత్యేకం! 🔥 పెసరట్టు + ఫిల్టర్ కాఫీ కాంబో ₹70 మాత్రమే! రండి ఆస్వాదించండి! ☕🥘', NULL, 89, 15, FALSE, FALSE, '2026-05-16T13:28:49.256Z'::timestamp, '2026-05-16T13:28:49.256Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxew00a6mavtgvcyp35s', 'cmp8dtxeq009mmavtdrwsucg2', 'cmp8dtxbf000cmavt5aq9r3xj', 'చాలా బాగుంది సర్! రోడ్లు బాగుపడితే ట్రాఫిక్ సమస్య తీరుతుంది 👏', '2026-05-16T13:28:49.257Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxex00a8mavtune8lu0j', 'cmp8dtxeq009mmavtdrwsucg2', 'cmp8dtxbc0006mavt3bpkbux9', 'మా షాపు ముందు రోడ్ చాలా చెడుగా ఉంది. దయచేసి త్వరగా పనులు మొదలుపెట్టండి 🙏', '2026-05-16T13:28:49.257Z'::timestamp) ON CONFLICT DO NOTHING;
